function ReportUtil:getUserId()
    local players = PlayerManager:getPlayers()
    if players ~= nil and players[1] ~= nil then
        return players[1].userId
    end
    return 0
end

function ReportUtil:getKeyByTime(time)
    if time <= 30 then
        return "0_30"
    elseif time <= 60 then
        return "30_60"
    elseif time <= 120 then
        return "60_120"
    elseif time <= 180 then
        return "120_180"
    elseif time <= 480 then
        return "180_480"
    else
        return "480a"
    end
end

function ReportUtil:getKeyByTimes(times)
    if times <= 10 then
        return tostring(times)
    end
    return "10a"
end

function ReportUtil:getKeyByDeadType(type, id, meta)
    if type == self.DeadType.Event then
        return self.DeadType.Event + tonumber(id)
    elseif type == self.DeadType.Skill then
        return self.DeadType.Skill + tonumber(id)
    elseif type == self.DeadType.Item then
        return self.DeadType.Item + tonumber(id) * 100 + tonumber(meta)
    else
        return type
    end
end

