function ReportUtil:reportBreakBlock(time)
    if self.BreakBlock == nil then
        return
    end
    local timeKey = self:getKeyByTime(time)
    for _, block in pairs(self.BreakBlock) do
        local parts = { "g1054_Break_Block", "Time" .. timeKey, "BlockId" .. block.id, "Num" .. block.num }
        GameAnalytics:design(self:getUserId(), 0, parts)
    end
    self.BreakBlock = {}
end

